procedures.TblAlertEventDA_SrchAbyssEventID:
create proc [dbo].[TblAlertEventDA_SrchAbyssEventID]
			@world_id nvarchar(3),			
			@event_id nvarchar(30),
			@from_date nvarchar(30),
			@to_date nvarchar(30),
			@event_info nvarchar(30)
		as
			set nocount on
			set transaction isolation level read uncommitted
			set ansi_warnings off	
			
			declare @sql nvarchar(300)
						
			set @sql = ' select top 1 ALERT_EVENT_ID, WORLD_ID, EVENT_ID, EVENT_INFO, convert(float,regdate,20) regdate from tbl_alert_event(nolock) ' +
					   ' where world_id='''+@world_id+''' and event_id='''+@event_id+''' and event_info like '''+@event_info+''' and regdate between '''+@from_date+''' and '''+@to_date+'''   '					  
												
			exec Sp_ExecuteSQL @sql
			
			set nocount off
			return

