procedures.TblGameNoticeScheduleDA_SrchReservedSche:
CREATE proc [dbo].[TblGameNoticeScheduleDA_SrchReservedSchedule]
			@current_time nvarchar(30),
			@period_hour nvarchar(2),
			@period_min nvarchar(2),
			@notice_status char(1)
		as
			set nocount on
			set transaction isolation level read uncommitted
			
			select NOTICE_RACE, NOTICE_CLASS, notice_pos_type, notice_id, notice_repeat, notice_repeat_min, notice_category, notice_subject, notice_type, notice_from, notice_to, notice_period, notice_week, notice_month, period_hour, period_min, communication_cd, notice_count, notice_status, login_id, convert(nvarchar,regdate,20) regdate 
			from TBL_GAME_NOTICE_SCHEDULE(nolock)
			where ((NOTICE_TO >= @current_time and NOTICE_FROM <= @current_time and PERIOD_HOUR = @period_hour AND PERIOD_MIN = @period_min) or (NOTICE_TO >= @current_time and NOTICE_FROM <= @current_time and notice_repeat_min != 0) or (notice_period = 'ONCE' and communication_cd = 'BEF'))			
			AND NOTICE_STATUS = @notice_status
			and communication_cd != 'TRA'
			order by regdate ASC
